public async Task<bool> PurchaseTicketsAsync(int eventId, int requestedQuantity)
{
    using (var context = new EventBookingContext())
    {
        using (var transaction = await context.Database.BeginTransactionAsync())
        {
            try
            {
                var eventEntity = await context.Events
                    .Where(e => e.Id == eventId)
                    .SingleOrDefaultAsync();

                if (eventEntity == null || eventEntity.AvailableSeats < requestedQuantity)
                {
                    return false; // Not enough seats available
                }

                eventEntity.AvailableSeats -= requestedQuantity;

                context.Events.Update(eventEntity);
                await context.SaveChangesAsync();

                await transaction.CommitAsync();
                return true; // Purchase successful
            }
            catch (DbUpdateConcurrencyException)
            {
                // Handle concurrency conflicts
                await transaction.RollbackAsync();
                return false; // Conflict occurred
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
                throw; // Re-throw unexpected exceptions
            }
        }
    }
